import React from "react";
import "bootstrap/dist/css/bootstrap.min.css";

export default function LandingPage() {
  return (
    <div className="bg-dark text-light">
      {/* Navbar */}
      <nav className="navbar navbar-expand-lg navbar-dark bg-dark fixed-top shadow">
        <div className="container">
          <a className="navbar-brand fw-bold text-info" href="#">
            Techvruk
          </a>
          <button
            className="navbar-toggler"
            data-bs-toggle="collapse"
            data-bs-target="#nav"
          >
            <span className="navbar-toggler-icon"></span>
          </button>
          <div className="collapse navbar-collapse" id="nav">
            <ul className="navbar-nav ms-auto">
              <li className="nav-item">
                <a className="nav-link" href="#programs">
                  Programs
                </a>
              </li>
              <li className="nav-item">
                <a className="nav-link" href="#community">
                  Community
                </a>
              </li>
              <li className="nav-item">
                <a className="nav-link" href="#contact">
                  Contact
                </a>
              </li>
            </ul>
            <button className="btn btn-info ms-3">Join Now</button>
          </div>
        </div>
      </nav>

      {/* Hero */}
      <section
        className="text-center d-flex align-items-center justify-content-center"
        style={{
          height: "100vh",
          background: "linear-gradient(90deg,#0f172a,#1e293b)",
        }}
      >
        <div className="container mt-5 pt-5">
          <h1 className="display-4 fw-bold">
            Build the Future with <span className="text-info">Techvruk</span>
          </h1>
          <p className="lead mt-3">
            Empowering engineers through innovation, training, and
            collaboration.
          </p>
          <div className="mt-4">
            <button className="btn btn-info me-3">Join Now</button>
            <button className="btn btn-outline-light">Explore Programs</button>
          </div>
        </div>
      </section>

      {/* Value Proposition */}
      <section className="py-5 bg-secondary bg-opacity-10 text-center">
        <div className="container">
          <div className="row g-4">
            {[
              "Innovation Contests",
              "Industry Training",
              "Awards & Recognition",
              "Networking",
            ].map((item, i) => (
              <div className="col-md-3" key={i}>
                <div className="card bg-dark text-light h-100 border-0 shadow">
                  <div className="card-body">
                    <h5>{item}</h5>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* How it works */}
      <section className="py-5 text-center">
        <div className="container">
          <h2 className="fw-bold mb-4">Your Engineering Journey</h2>
          <div className="row g-4">
            {["Sign Up", "Learn & Participate", "Get Recognized"].map(
              (step, i) => (
                <div className="col-md-4" key={i}>
                  <div className="p-4 border rounded bg-dark">
                    <h5>{step}</h5>
                  </div>
                </div>
              ),
            )}
          </div>
        </div>
      </section>

      {/* Programs */}
      <section id="programs" className="py-5 bg-secondary bg-opacity-10">
